import os

fn cycle_length(mut memo map[u64]u64, n u64) u64 {
	if n == 1 {
		return 1
	}

	if n in memo {
		return memo[n]
	}

	length:= if n%2 == 0 {
		1+ cycle_length(mut memo,n/2)
	} else {
		1+cycle_length(mut memo,3*n+1)
	}

	memo[n] = length
	return length
}

